async (params, browser) => {
  // Open matches
  await browser.open('https://tinder.com/app/matches')

  // Wait for matches
  await browser.waitForSelector('[class*="matchList"], [class*="matches"], .content', 15000)

  // Let matches render
  await browser.wait(2500)

  // Extract matches
  const result = await browser.evaluate(`const matches = []; const seen = new Set(); document.querySelectorAll('a[href*="/app/messages/"], [class*="matchList"] a, [class*="messageListItem"] a, [class*="match"] a').forEach((el) => { const href = el.href || ''; if (seen.has(href) || matches.length >= 20) return; seen.add(href); const nameEl = el.querySelector('[class*="name"], span'); const msgEl = el.querySelector('[class*="message"], [class*="preview"], [class*="msg"]'); matches.push({ name: nameEl?.textContent?.trim() || '', last_message: msgEl?.textContent?.trim() || '', url: href }); }); return { match_count: matches.length, matches };`)

  return result
}
